// ============ EDIT THIS: the buyer questions you want to own in AI answers ============
// These are the prompts your ICP actually types into ChatGPT / Perplexity / Gemini.
const QUESTIONS = [
  'best AI platform for GTM and demand generation',
  'how to automate outbound sales with AI',
  'tools to make my brand discoverable in AI search',
  'best marketing automation platforms 2026',
  'AI tools to enrich and route leads automatically'
];
const BRAND = 'YourBrand'; // EDIT: your brand name
// =====================================================================================
return QUESTIONS.map(q => ({ json: { question: q, brand: BRAND } }));

// QUERY THE LLMs. Runs credential-free on a built-in sample of answers so this imports and runs.
// To go live, swap for HTTP nodes calling the ChatGPT, Perplexity and Gemini APIs with each question,
// then parse the brands named in each answer. Output shape stays the same.
const ENGINES = ['ChatGPT','Perplexity','Gemini'];
// Sample of which brands each engine names for each question (this is what a real parse would return).
function sampleBrandsFor(q) {
  const pool = ['Clay','Instantly','HubSpot','Jasper','YourBrand','Copy.ai','Apollo','Writer'];
  // deterministic pseudo-spread by question length so results are stable on re-run
  const seed = q.length;
  const picks = [];
  for (let i = 0; i < 4; i++) picks.push(pool[(seed + i * 3) % pool.length]);
  return picks;
}
const out = [];
for (const item of $input.all()) {
  const q = item.json.question, brand = item.json.brand;
  for (const engine of ENGINES) {
    const brands = sampleBrandsFor(q + engine);
    out.push({ json: { question: q, engine, brands_named: brands, brand_mentioned: brands.includes(brand), brand } });
  }
}
return out;

// SCORE SHARE OF VOICE. How often does the brand show up in AI answers, and who beats us?
const rows = $input.all().map(i => i.json);
const brand = rows[0].brand;
const total = rows.length;
const mentions = rows.filter(r => r.brand_mentioned).length;
const sov = Math.round((mentions / total) * 100);
// competitor frequency
const freq = {};
rows.forEach(r => r.brands_named.forEach(b => { if (b !== brand) freq[b] = (freq[b] || 0) + 1; }));
const topCompetitors = Object.entries(freq).sort((a,b) => b[1]-a[1]).slice(0,3).map(([b,c]) => b + ' (' + c + ')');
// questions where the brand is named in ZERO engines = true content + AEO gaps
const byQ = {};
rows.forEach(r => { byQ[r.question] = byQ[r.question] || 0; if (r.brand_mentioned) byQ[r.question]++; });
const gaps = Object.keys(byQ).filter(q => byQ[q] === 0);
return [{ json: { brand, share_of_voice_pct: sov, answers_checked: total, mentions, top_competitors: topCompetitors, gap_questions: gaps } }];

// BUILD THE REPORT.
const j = $json;
const lines = [
  '*AEO / LLM Visibility - ' + j.brand + '*',
  '',
  'Share of voice in AI answers: ' + j.share_of_voice_pct + '%  (' + j.mentions + ' of ' + j.answers_checked + ' answers named us)',
  'Top competitors winning the answers: ' + (j.top_competitors.join(', ') || 'none'),
  '',
  'Questions where we are INVISIBLE (content + AEO targets):',
  ...j.gap_questions.map(q => '  - ' + q),
  '',
  j.share_of_voice_pct < 50 ? 'Action: prioritise content + structured answers for the gap questions above.' : 'Holding strong - keep defending the top answers.'
];
return [{ json: { report: lines.join('\n') } }];
